define i32 @reduce_and_sext_i8(<4 x i8> %x) {
  %sext = sext <4 x i8> %x to <4 x i32>
  %res = call i32 @llvm.vector.reduce.and.v4i32(<4 x i32> %sext)
  ret i32 %res
}

